// // This comment suggests that the flip-flop will set the output to its current value on every rising edge of the clock when the toggle signal is high.
module toggle_ff(clk, t, q);  

    input  clk;  
    input t;  
    output  q;  
    reg   q; 

    always @(posedge clk)
          begin
            if (t)
                q <= ~q;
          end  

endmodule
